+ public Order checkout(Long userId, CheckoutRequest request) {
+     User user = userRepository.findById(userId).get();
+     Order order = new Order();
+     order.setUserId(userId);
+     order.setStatus("PAID");
+     for (CartItem item : request.items()) {
+         Product product = productRepository.findById(item.productId()).get();
+         if (product.getStock() < item.quantity()) {
+             throw new RuntimeException("stock not enough");
+         }
+         product.setStock(product.getStock() - item.quantity());
+         productRepository.save(product);
+         order.addLine(product.getId(), item.quantity(), product.getPrice());
+     }
+     paymentClient.charge(user.getCardToken(), order.totalAmount());
+     emailClient.send(user.getEmail(), "checkout success");
+     return orderRepository.save(order);
+ }
+
+ public List<Order> search(String keyword) {
+     String sql = "SELECT * FROM orders WHERE note LIKE '%" + keyword + "%'";
+     return jdbcTemplate.query(sql, orderMapper);
+ }
+
+ public void cancel(Long orderId) {
+     Order order = orderRepository.findById(orderId).get();
+     order.setStatus("CANCELLED");
+     orderRepository.save(order);
+ }
